// Calculate the previous week date range (Monday-Sunday)
const now = new Date();
const dayOfWeek = now.getDay(); // 0=Sun, 1=Mon...

// Find this Monday
const thisMonday = new Date(now);
const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
thisMonday.setDate(now.getDate() + diffToMonday);
thisMonday.setHours(0, 0, 0, 0);

// Previous Monday
const prevMonday = new Date(thisMonday);
prevMonday.setDate(thisMonday.getDate() - 7);

// Previous Sunday
const prevSunday = new Date(prevMonday);
prevSunday.setDate(prevMonday.getDate() + 6);
prevSunday.setHours(23, 59, 59, 999);

return {
  since: prevMonday.toISOString(),
  until: prevSunday.toISOString(),
  weekLabel: prevMonday.toISOString().split('T')[0] + ' to ' + prevSunday.toISOString().split('T')[0]
};

// Filter only merged PRs (closed + merged_at !== null)
const items = $input.all();
const mergedPRs = items.filter(item => {
  const pr = item.json;
  return pr.merged_at !== null && pr.state === 'closed';
});

// Return just the JSON array
return mergedPRs.map(item => item.json);

// Combine all data sources and build the Claude API request body

// Get config
const config = $("Configure Variables").first().json;

// Get commits
const commits = $("GitHub: Get Commits").all().map(i => ({
  sha: (i.json.sha || '').substring(0, 7),
  message: (i.json.commit?.message || '').split('\n')[0],
  author: i.json.commit?.author?.name || 'unknown',
  date: i.json.commit?.author?.date || ''
}));

// Get closed issues (filter out PRs)
const issues = $("GitHub: Get Closed Issues").all()
  .filter(i => !i.json.pull_request)
  .map(i => ({
    number: i.json.number,
    title: i.json.title,
    author: i.json.user?.login || 'unknown',
    labels: (i.json.labels || []).map(l => l.name),
    closedAt: i.json.closed_at
  }));

// Get filtered merged PRs
const prs = $("Filter Merged PRs").all().map(i => ({
  number: i.json.number,
  title: i.json.title,
  author: i.json.user?.login || 'unknown',
  additions: i.json.additions || 0,
  deletions: i.json.deletions || 0,
  mergedAt: i.json.merged_at
}));

// Stats
const stats = {
  totalCommits: commits.length,
  totalIssues: issues.length,
  totalPRs: prs.length,
  totalAdditions: prs.reduce((sum, p) => sum + p.additions, 0),
  totalDeletions: prs.reduce((sum, p) => sum + p.deletions, 0)
};

// Build the prompt for Claude
const lang = config.language === 'FR' ? 'French' : 'English';
const dateRange = $("Calculate Date Range").first().json.weekLabel;

let prompt = 'Generate a weekly development summary for the repository **' + config.repoOwner + '/' + config.repoName + '** covering the period **' + dateRange + '**.\n\n';
prompt += 'Write the response in **' + lang + '**. Use a professional but engaging tone.\n\n';
prompt += '## Weekly Statistics\n';
prompt += '- Commits: ' + stats.totalCommits + '\n';
prompt += '- Closed Issues: ' + stats.totalIssues + '\n';
prompt += '- Merged PRs: ' + stats.totalPRs + '\n';
prompt += '- Lines Added: ' + stats.totalAdditions + '\n';
prompt += '- Lines Removed: ' + stats.totalDeletions + '\n\n';

if (commits.length > 0) {
  prompt += '## Notable Commits\n';
  commits.slice(0, 30).forEach(c => {
    prompt += '- `' + c.sha + '` ' + c.message + ' (' + c.author + ')\n';
  });
  prompt += '\n';
}

if (issues.length > 0) {
  prompt += '## Closed Issues\n';
  issues.slice(0, 20).forEach(issue => {
    prompt += '- #' + issue.number + ': ' + issue.title + ' (by ' + issue.author + ')\n';
  });
  prompt += '\n';
}

if (prs.length > 0) {
  prompt += '## Merged Pull Requests\n';
  prs.slice(0, 20).forEach(pr => {
    prompt += '- #' + pr.number + ': ' + pr.title + ' (+' + pr.additions + '/-' + pr.deletions + ' lines, by ' + pr.author + ')\n';
  });
  prompt += '\n';
}

prompt += '## Format Requirements\n';
prompt += '1. Start with an executive summary (2-3 sentences)\n';
prompt += '2. Include a "Key Highlights" section with top 3 achievements\n';
prompt += '3. Add a "Stats at a Glance" table\n';
prompt += '4. Categorize changes into: Features, Bug Fixes, Refactoring, Documentation\n';
prompt += '5. End with a forward-looking note for next week\n';
prompt += '6. Use Markdown formatting throughout\n';

// Return both the Claude request and summary data
return {
  claudeRequest: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 2048,
    messages: [
      {
        role: 'user',
        content: prompt
      }
    ]
  },
  summaryData: {
    repoOwner: config.repoOwner,
    repoName: config.repoName,
    weekLabel: dateRange,
    language: config.language,
    stats: stats
  }
};

// Extract Claude's response and format for delivery
const claudeResponse = $input.first().json;
const contentBlocks = claudeResponse.content || [];

// Claude returns content as array of content blocks
const markdown = contentBlocks
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n');

const summaryData = $("Build Summary & Claude Request").first().json.summaryData;

return {
  markdown: markdown,
  repo: summaryData.repoOwner + '/' + summaryData.repoName,
  weekLabel: summaryData.weekLabel
};

